  static List<Map<String, dynamic>> get sablonlar {
    try {
      final raw = jsonDecode(_seedJson);
      if (raw is! List) return const [];
      final list = raw
          .map((e) => Map<String, dynamic>.from(e as Map))
          .toList(growable: true);
      final ekSablonlar = <Map<String, dynamic>>[_satisFisi3, _satisFisi4];
      for (final sablon in ekSablonlar) {
        final name = (sablon['name'] ?? '').toString().trim();
        final docType = (sablon['doc_type'] ?? '').toString().trim();
        final mevcut = list.any(
          (mevcutSablon) =>
              (mevcutSablon['name'] ?? '').toString().trim() == name &&
              (mevcutSablon['doc_type'] ?? '').toString().trim() == docType,
        );
        if (!mevcut) {
          list.add(Map<String, dynamic>.from(sablon));
        }
      }
      return List.unmodifiable(list);
    } catch (_) {
      return const [];
    }
  }
